import myOpenGL     from '../../myOpenGL.js'

// Hàm đọc file JSON (có thể bỏ vào DialogueAPI hoặc js_glue.js)
const LoadIngredientsDB = async function(_f) {
  try {
    const response = await fetch(`${_f}?t=${Date.now()}`);
    const data = await response.json();
    return data;
  } catch (err) {
    console.error("❌ Lỗi nạp dữ liệu nguyên liệu:", err);
    return [];
  }
};

// 2. Hàm tiện ích để biến URL thành đối tượng Image (HTMLImageElement)
const loadImage = (url) => {
  return new Promise((resolve, reject) => {
    const image = new Image();
    image.src = url;
    image.onload = () => resolve(image);
    image.onerror = (err) => reject(new Error("Không thể tải ảnh tại: " + url));
  });
};

async function init_gl(id, food_name) {
  var _id = id.slice(-3);
  const response = await fetch("./resources/mathNote/shader/frag_cook.glsl");
  const fragSrc = await response.text();

  var gl = myOpenGL.GLInstance(`cv_${_id}`);
  gl.clearColor(0.0, 0.0, 0.0, 1.0);
  gl.fClear();
  
  // Lưu lại ID canvas để dễ quản lý
  gl._canvasId = `cv_${_id}`;

  await myOpenGL.glRun(gl);

  const imageModule = await import(`/resources/items/ingredients_${food_name}.png`);
  const actualImageElement = await loadImage(imageModule.default);
  gl.fLoadTexture("tex001", actualImageElement, true);

  gl.gShader = new myOpenGL.ThuyShader(gl, gl.gCamera.projectionMatrix, fragSrc)
    .activate() // Quan trọng: Kích hoạt shader
    .setTexture(gl.mTextureCache["tex001"], "uMainTex");

  return gl;
}

// window._shader_btn_click = _shader_btn_click;

export default async function(Module, entityId, C, API) {
  const e = window.App.entities[window.App.C.GetEntityName(entityId)];
  const speakerName = e.name;
  const food_name = speakerName;
  const ingredients = await LoadIngredientsDB(`/resources/json/${food_name}.json`); 
  let needToPlayAudio = true; 

  // if (window.thuy_gl === undefined) {
    // Đợi cho UI vẽ xong canvas rồi mới init (Dùng setTimeout 0 để đẩy vào hàng đợi)
    setTimeout(async () => {
      window.thuy_gl = await init_gl("001", food_name);
      // Sau khi init xong, set vị trí đầu tiên
      updateShaderOffset(ingredients[e.npcProgress.solved]);
    }, 50);
  // }

  var cv = document.getElementById(`cv_001`);
  cv.style.display = 'block';

  // Hàm phụ để cập nhật offset cho đỡ rối code
  function updateShaderOffset(item, glInstance) {
    if(!glInstance && window.thuy_gl instanceof Promise) return;
    const gl = glInstance || window.thuy_gl;

    const x = item.col;
    const y = item.row; // Đảo ngược Y để khớp WebGL

    gl.gShader.activate().setVec2('u_offset', x, y);
    // gl.gShader.activate().setVec2('u_offset', 2, 3);
    // Nếu framework không tự render, hãy gọi lệnh vẽ ở đây
    // gl.fRender(); 
    console.log(x,y);
  }

  while (e.npcProgress.solved < e.npcProgress.total) {
    let currentScore = e.npcProgress.solved;
    const targetItem = ingredients[currentScore];

    // 1. Chuẩn bị câu hỏi (Canvas phải có trong chuỗi này)
    const questionText = `### 🍕 Cùng làm ${food_name} nào! (${currentScore}/${e.npcProgress.total})`;

    // 2. Xử lý khởi tạo GL (Chỉ khởi tạo 1 lần duy nhất)
    if (window.thuy_gl) {
      // Nếu đã có rồi thì chỉ việc cập nhật offset
      // Dùng await vì window.thuy_gl có thể đang là Promise nếu chưa xong
      const gl = await window.thuy_gl;
      updateShaderOffset(targetItem, gl);
    }

    // 3. Chuẩn bị choices và gọi Ask... (Giữ nguyên logic cũ của bạn)
    const wrongPool = ingredients.filter(item => item.en !== targetItem.en).sort(() => Math.random() - 0.5);
    const choices = [
      { text: `**${targetItem.en}**`, isCorrect: true },
      { text: wrongPool[0].en, isCorrect: false },
      { text: wrongPool[1].en, isCorrect: false }
    ].sort(() => Math.random() - 0.5);
    choices.unshift({ text: "🔊 Nghe lại", isAudioBtn: true });

    window.SpeakText(targetItem.en, 'en-US', 0.85);

    const selectedIdx = await API.Ask(entityId, speakerName, questionText, choices.map(c => c.text));

    if (selectedIdx === -1) {
      return false;
    }

    const selectedChoice = choices[selectedIdx];

    // --- KIỂM TRA LỰA CHỌN ---
    if (selectedChoice.isAudioBtn) {
      window.SpeakText(targetItem.en, 'en-US', 0.85);
      continue;
    }

    if (selectedChoice.isCorrect) {
      // currentScore++;
      window.TriggerFeedback(true);
      needToPlayAudio = true; 
      window.UpdateQuestProgress(entityId,true); 
      window.SpeakText(targetItem.en, 'en-US', 0.85);

    } else {
      window.TriggerFeedback(false);
      window.SpeakText(targetItem.en, 'en-US', 0.85);
      await API.Say(entityId, speakerName, `### ❌ Chưa đúng rồi!\n\nHình đó là món **${targetItem.en}** (${targetItem.vi}).\nBé nghe lại và chọn cho đúng nhé!`);
    }
  }

  cv.style.display = 'none';
  window.SpeakText("Hoàn thành xuất sắc!", 'vi-VN', 1.0, 1.2);

  await API.Say(entityId, speakerName, "### 👨‍🍳 Hoàn thành xuất sắc!\n\nChiếc Pizza đã được nướng xong. Cảm ơn đầu bếp nhí nhé!");

  // window.thuy_gl = undefined;

  return true; 
}
